  background-color: var(--color-background-brand-hover);
}

/* Focus state */
.c-button:focus-visible {
  outline: none;
  box-shadow: 0 0 0 3px var(--color-border-focus);
}

/* Active/pressed state */
.c-button:active:not([data-state="loading"]):not([data-state="disabled"]) {
  transform: scale(0.98);
}

/* ============================================ */
/* LOADING STATE — via data-state, not class    */
/* ============================================ */
.c-button[data-state="loading"] {
  /* Disable interaction */
  pointer-events: none;
  cursor: not-allowed;

  /* Visual feedback */
  opacity: 0.8;
  position: relative;

  /* Prevent text selection during loading */
  user-select: none;
}

/* Hide text, show spinner when loading */
.c-button[data-state="loading"] .c-button__text {
  visibility: hidden;
}

